    79→          id: fleet.id,
    80→          code: fleet.code,
    81→          name: fleet.name,
    82→          manufacturer: fleet.manufacturer,
    83→          model: fleet.model,
    84→          carsPerTrain: fleet.carsPerTrain,
    85→          trainCount: 0,
    86→          activeTrainCount: 0,
    87→        };
    88→      }
    89→    })
    90→  );
    91→
    92→  return c.json(
    93→    success(enrichedFleets, {
    94→      timing: { durationMs: getRequestDuration(c) },
    95→    })
    96→  );
    97→});
