/**
 * MMS Baseline Service Unit Tests
 *
 * Tests for the Baseline Service covering:
 * - Service initialization and singleton pattern
 * - Baseline version management
 * - Plan validation for publishing
 * - Mileage projection calculations
 * - Baseline lifecycle management
 * - Pagination and filtering
 *
 * Note: These tests use Bun's test framework and document expected behavior.
 * Integration tests with actual database should be in a separate test suite.
 *
 * @see src/services/baseline.ts
 */

import { describe, test, expect } from 'bun:test';
import {
  BaselineService,
  getBaselineService,
  type BaselineStatus,
  type BaselineListFilters,
  type BaselinePaginationOptions,
  type PublishBaselineRequest,
  type PlanConflict,
  type PlanWarning,
  type PlanValidationResult,
  type BaselineSummary,
} from './baseline';
import {
  NotFoundError,
  ValidationError,
  BusinessRuleError,
} from '../lib/errors';

describe('BaselineService', () => {
  describe('Initialization', () => {
    test('should create a BaselineService instance', () => {
      const service = new BaselineService();
      expect(service).toBeDefined();
      expect(service).toBeInstanceOf(BaselineService);
    });

    test('should return singleton instance via getBaselineService', () => {
      const instance1 = getBaselineService();
      const instance2 = getBaselineService();
      expect(instance1).toBe(instance2);
    });
  });

  describe('Type Definitions', () => {
    describe('BaselineStatus', () => {
      test('should support all baseline status values', () => {
        const statuses: BaselineStatus[] = ['DRAFT', 'PUBLISHED', 'SUPERSEDED', 'ARCHIVED'];
        expect(statuses).toHaveLength(4);
        expect(statuses).toContain('DRAFT');
        expect(statuses).toContain('PUBLISHED');
        expect(statuses).toContain('SUPERSEDED');
        expect(statuses).toContain('ARCHIVED');
      });
    });

    describe('BaselineListFilters', () => {
      test('should support single status filter', () => {
        const filters: BaselineListFilters = {
          status: 'PUBLISHED',
        };
        expect(filters.status).toBe('PUBLISHED');
      });

      test('should support multiple status filters', () => {
        const filters: BaselineListFilters = {
          status: ['PUBLISHED', 'SUPERSEDED'],
        };
        expect(Array.isArray(filters.status)).toBe(true);
        expect(filters.status).toContain('PUBLISHED');
        expect(filters.status).toContain('SUPERSEDED');
      });

      test('should support date range filters', () => {
        const filters: BaselineListFilters = {
          fromDate: new Date('2026-01-01'),
          toDate: new Date('2026-12-31'),
        };
        expect(filters.fromDate).toBeDefined();
        expect(filters.toDate).toBeDefined();
      });

      test('should support createdBy filter', () => {
        const filters: BaselineListFilters = {
          createdBy: 'user-123',
        };
        expect(filters.createdBy).toBe('user-123');
      });
    });

    describe('BaselinePaginationOptions', () => {
      test('should have sensible defaults when empty', () => {
        const pagination: BaselinePaginationOptions = {};
